SELECT student_id, name, department, COUNT(*) AS occurrence_count
FROM students
GROUP BY student_id, name, department;

SELECT AVG(grade_point) AS average_gpa_of_A
FROM grades
WHERE grade = 'A';

SELECT g.semester, AVG(g.gpa) AS average_gpa
FROM gpa_calculations g
GROUP BY g.semester;

SELECT COUNT(DISTINCT student_id) AS num_students_with_grade_A
FROM grades
WHERE grade = 'A';
